import { describe, it, expect } from 'vitest';
import { setJsonMode, isJsonMode, printJSON, printHuman } from '../src/utils/output';

describe('output', () => {
    it('should default to human mode', () => {
        setJsonMode(false);
        expect(isJsonMode()).toBe(false);
    });

    it('should switch to JSON mode', () => {
        setJsonMode(true);
        expect(isJsonMode()).toBe(true);
        setJsonMode(false); // reset
    });

    it('printJSON should write valid JSON to stdout', () => {
        const logs: string[] = [];
        const originalWrite = process.stdout.write;
        process.stdout.write = ((str: string) => { logs.push(str); return true; }) as any;

        printJSON({ test: true });

        process.stdout.write = originalWrite;
        expect(JSON.parse(logs[0])).toEqual({ test: true });
    });
});
